var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"그 여자는 샤레이드에서 가장 성공한 카운터예요.","JPN":"あの女は、シャレードでもっとも成功したカウンターです。","ENG":"She is the most successful Counter in all of Charade.","TWN":"那個女人是查雷德最成功的制裁者。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"경매에 나온 넘버링 태스크포스 라이선스를 돈으로 사들일 만큼.","JPN":"オークションに出たナンバリングタスクフォースライセンスを、お金で買い取るくらい。","ENG":"She's rich enough to buy a numbered TASKFORCE license in an auction.","TWN":"她甚至能夠砸錢買下拍賣的高級特遣勢力執照。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"처음 등장했을 당시에는, 모두가 동경하는 스타 플레이어였어요.","JPN":"最初に登場した時には、みんなが憧れるスタープレイヤーでした。","ENG":"When she first appeared, she was a star player beloved by everyone.","TWN":"剛出場的時候，她曾經是所有人憧憬的明星選手。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"언제나 정정당당하게 승리를 거두는 건틀렛의 우상.","JPN":"いつも正々堂々と勝利を収めるガントレットのアイドル。","ENG":"Gauntlet's idol, always winning fair and square.","TWN":"總是光明正大贏得比賽的聖鎧偶像。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"이번 건은 도가 지나쳤더군. 오지만디아스.","JPN":"今回の件は度が過ぎたな。オジマンディアス。","ENG":"You went too far this time, Ozymandias.","TWN":"你這次做得太過火了，奧茲曼迪亞斯。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아이, 그냥 조용히 처리해 줘. 우리 사이에.","JPN":"もう、目をつぶってくれない？　他でもない私の頼みでしょ？","ENG":"Oh, come on. Just cover it up. You can do that for me, right?","TWN":"唉唷，我們是什麼關係？就私下幫我處理一下嘛。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내가 다 알고 손을 댔겠어? 그냥 옛날 인연 때문에 좀 도와 주려다 그런 거지.","JPN":"全部知ってて手を出したわけじゃないわ。ただ、昔の縁でちょっと手伝ってあげようとしてこうなったの。","ENG":"It's not like I knew what would happen. It was all to help an old acquaintance.","TWN":"要是我知道的話怎麼會出手？我是看在過去的情分才幫忙的。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>의도는 좋았다</color> 같은 말도 있잖아.","JPN":"<color=#ffd34c>意図はよかった</color>って言葉もあるじゃない？","ENG":"You know how the saying goes: <color=#ffd34c>It's the thought that counts</color>.","TWN":"畢竟我的<color=#ffd34c>出發點是好的</color>嘛。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"이건 관리국과도 깊이 연관된 문제야. 더 이상은 개입하지 마라.","JPN":"これは管理局とも深く関わっている問題だ。これ以上は干渉するな。","ENG":"This is also related to the Administration. Do not interfere anymore.","TWN":"這件事關係到管理局，不准你再插手。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"벌벌 떠는 소리가 여기까지 들리겠네.","JPN":"ぶるぶる震える音、ここまで聞こえちゃうわね。","ENG":"I hear you trembling from right over there.","TWN":"從電話裡都聽得出來你的聲音在發抖呢。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"나 이제 집이야. 자세한 얘기는 얼굴 보고 얘기해.","JPN":"私、もう家に着いたわ。詳しい話は直接顔を合わせてしましょう。","ENG":"I'm home now. Let's talk more in person.","TWN":"我現在在家，詳細的事等見面再說吧。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 스캐빈저에서 선물도 보내 줬나 봐.","JPN":"ふふ、スカベンジャーからプレゼントも贈ってくれたようね。","ENG":"Fu fuu, it looks like Scavengers sent me a little gift.","TWN":"呵呵，清道夫還送禮物來給我嗎？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"오지만디아스, 플라티나가 널 언제까지 비호해 줄 거라고─","JPN":"オジマンディアス、プラチナがいつまでも君を庇護してくれると─","ENG":"Ozymandias, just how long do you think Platina is going to protect y–","TWN":"奧茲曼迪亞斯，你以為普拉提娜會保你到什麼時候—"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그러게나 말이야. 나도 궁금해지네.","JPN":"そうね。私も気になるわ。","ENG":"Tell me about it. I'm curious myself.","TWN":"就是說，我也很好奇呢。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어디 보자, 오늘 파티 일정이~","JPN":"どれどれ、今日のパーティースケジュールは～","ENG":"Let's see, today's party schedule is...","TWN":"我來看看今天的派對行程～"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"음? 격발음?","JPN":"うん？　撃発の音？","ENG":"Hmm? This sound is?","TWN":"嗯？爆炸聲？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);exp